1	type Item = { type: string };
2	type Scenario = { steps: Array<{ op: string; items: Array<Item> }> };
3	
4	const PROCESSING_FEE = 5;
5	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	};
14	
15	function quoteItem(item: Item): number {
16	  const basePremium = BASE_PREMIUMS[item.type];
17	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
18	  return basePremium + firstInsuranceSurcharge;
19	}
20	
21	export function processScenario(scenario: unknown): { results: Array<{ premium?: number }> } {
22	  const { steps } = scenario as Scenario;
23	  const itemsPremium = steps[0].items.reduce((sum, item) => sum + quoteItem(item), 0);
24	  const premium = Math.ceil(itemsPremium + PROCESSING_FEE);
25	  return { results: [{ premium }] };
26	}
